Remember-me functionality is a common feature but extremely dangerous when implemented incorrectly. Many breaches stem from predictable tokens, lack of token rotation, or storing sensitive data in cookies.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/base64"
	"fmt"
	"net/http"
	"time"
)

type User struct {
	ID       int
	Username string
	Password string
}

// VULNERABLE: Predictable remember-me token generation
func generateRememberToken(user *User) string {
	// BAD: Token is predictable - just base64 of username:userID
	token := base64.StdEncoding.EncodeToString(
		[]byte(fmt.Sprintf("%s:%d", user.Username, user.ID)),
	)
	return token
}

func loginHandler(w http.ResponseWriter, r *http.Request) {
	username := r.FormValue("username")
	password := r.FormValue("password")
	rememberMe := r.FormValue("remember_me") == "on"

	// Assume user authenticated successfully
	user := &User{ID: 1, Username: username, Password: password}

	if rememberMe {
		token := generateRememberToken(user)
		// BAD: No HttpOnly, no Secure, excessive expiration
		http.SetCookie(w, &http.Cookie{
			Name:    "remember_token",
			Value:   token,
			Expires: time.Now().Add(365 * 24 * time.Hour), // 1 year!
			Path:    "/",
		})
	}

	http.Redirect(w, r, "/dashboard", http.StatusFound)
}

func validateRememberToken(w http.ResponseWriter, r *http.Request) {
	cookie, err := r.Cookie("remember_token")
	if err != nil {
		http.Redirect(w, r, "/login", http.StatusFound)
		return
	}

	// BAD: Token never expires, never rotated, no server-side validation
	decoded, _ := base64.StdEncoding.DecodeString(cookie.Value)
	// Directly trust the token content
	fmt.Fprintf(w, "Welcome back: %s", string(decoded))
}
```

**Attack Payload**:
```bash
# Attacker can generate valid tokens for any user
echo -n "admin:1" | base64
# Result: YWRtaW46MQ==

# Set forged cookie to hijack admin account
curl -b "remember_token=YWRtaW46MQ==" https://vulnerable-app.com/dashboard
```

**Why This Is Dangerous**:
- Token is predictable (base64 of known values) - attacker can forge tokens for any user
- No cryptographic signature or HMAC to prevent tampering
- Token never expires server-side (only cookie expiration)
- Cookie lacks HttpOnly flag (vulnerable to XSS theft)
- Cookie lacks Secure flag (sent over HTTP)
- No token rotation on use or password change
- No way to invalidate stolen tokens

**SECURE VERSION**:

```go
package main

import (
	"crypto/rand"
	"crypto/sha256"
	"database/sql"
	"encoding/hex"
	"net/http"
	"time"

	_ "github.com/lib/pq"
)

type RememberToken struct {
	ID           int
	UserID       int
	Selector     string // Public identifier
	HashedToken  string // Hashed validator (never stored in plain text)
	ExpiresAt    time.Time
	CreatedAt    time.Time
	LastUsedAt   time.Time
	UserAgent    string
	IPAddress    string
}

var db *sql.DB

// SECURE: Generate cryptographically random tokens
func generateSecureToken(length int) (string, error) {
	bytes := make([]byte, length)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes), nil
}

// SECURE: Hash the validator portion before storage
func hashToken(token string) string {
	hash := sha256.Sum256([]byte(token))
	return hex.EncodeToString(hash[:])
}

func createRememberToken(userID int, r *http.Request) (string, error) {
	// Generate selector (public) and validator (secret)
	selector, err := generateSecureToken(16)
	if err != nil {
		return "", err
	}
	validator, err := generateSecureToken(32)
	if err != nil {
		return "", err
	}

	// Store hashed validator in database
	hashedValidator := hashToken(validator)
	expiresAt := time.Now().Add(30 * 24 * time.Hour) // 30 days max

	_, err = db.Exec(`
		INSERT INTO remember_tokens 
		(user_id, selector, hashed_token, expires_at, created_at, user_agent, ip_address)
		VALUES ($1, $2, $3, $4, NOW(), $5, $6)`,
		userID, selector, hashedValidator, expiresAt,
		r.UserAgent(), r.RemoteAddr,
	)
	if err != nil {
		return "", err
	}

	// Return selector:validator to client (validator is NOT stored)
	return selector + ":" + validator, nil
}

func secureLoginHandler(w http.ResponseWriter, r *http.Request) {
	// ... authentication logic ...
	userID := 1 // Authenticated user ID
	rememberMe := r.FormValue("remember_me") == "on"

	if rememberMe {
		token, err := createRememberToken(userID, r)
		if err != nil {
			http.Error(w, "Internal error", http.StatusInternalServerError)
			return
		}

		// SECURE: Proper cookie attributes
		http.SetCookie(w, &http.Cookie{
			Name:     "remember_token",
			Value:    token,
			Expires:  time.Now().Add(30 * 24 * time.Hour),
			Path:     "/",
			HttpOnly: true,  // Prevents XSS theft
			Secure:   true,  // HTTPS only
			SameSite: http.SameSiteStrictMode, // CSRF protection
		})
	}

	http.Redirect(w, r, "/dashboard", http.StatusFound)
}
```

**Key Security Controls**:
- **Cryptographically random tokens**: Uses `crypto/rand` for unpredictable 48-byte tokens (selector + validator)
- **Split token design**: Selector identifies the record, hashed validator proves ownership - prevents timing attacks on lookups
- **Server-side expiration**: Tokens expire in database, not just cookies
- **Secure cookie attributes**: HttpOnly, Secure, SameSite=Strict prevent common attacks
- **Context binding**: Stores user agent and IP for anomaly detection

Excellent questions! Token validation and lifecycle management are critical for remember-me security. You need constant-time comparison, automatic rotation, and proper invalidation on security events.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/rand"
	"crypto/sha256"
	"crypto/subtle"
	"database/sql"
	"encoding/hex"
	"errors"
	"log/slog"
	"net/http"
	"os"
	"strings"
	"time"

	_ "github.com/lib/pq"
)

var (
	ErrInvalidToken     = errors.New("invalid or expired token")
	ErrTokenCompromised = errors.New("token potentially compromised")
	logger              = slog.New(slog.NewJSONHandler(os.Stdout, nil))
)

type TokenService struct {
	db              *sql.DB
	maxTokenAge     time.Duration
	rotationPeriod  time.Duration
	maxTokensPerUser int
}

type TokenValidationResult struct {
	UserID       int
	TokenID      int
	NeedsRotation bool
	NewToken     string
}

func NewTokenService(db *sql.DB) *TokenService {
	return &TokenService{
		db:              db,
		maxTokenAge:     30 * 24 * time.Hour, // 30 days
		rotationPeriod:  24 * time.Hour,      // Rotate daily
		maxTokensPerUser: 5,                  // Limit active sessions
	}
}

// ValidateAndRotateToken validates a remember-me token with security best practices
func (ts *TokenService) ValidateAndRotateToken(ctx context.Context, tokenValue string, r *http.Request) (*TokenValidationResult, error) {
	// Parse selector:validator format
	parts := strings.SplitN(tokenValue, ":", 2)
	if len(parts) != 2 || len(parts[0]) != 32 || len(parts[1]) != 64 {
		logger.Warn("malformed remember token",
			"ip", r.RemoteAddr,
			"user_agent", r.UserAgent(),
		)
		return nil, ErrInvalidToken
	}

	selector := parts[0]
	validator := parts[1]

	// Look up token by selector (constant-time safe)
	var storedToken struct {
		ID          int
		UserID      int
		HashedToken string
		ExpiresAt   time.Time
		LastUsedAt  time.Time
		UserAgent   string
		IPAddress   string
	}

	err := ts.db.QueryRowContext(ctx, `
		SELECT id, user_id, hashed_token, expires_at, last_used_at, user_agent, ip_address
		FROM remember_tokens 
		WHERE selector = $1 AND revoked = FALSE
		FOR UPDATE`, selector).Scan(
		&storedToken.ID, &storedToken.UserID, &storedToken.HashedToken,
		&storedToken.ExpiresAt, &storedToken.LastUsedAt,
		&storedToken.UserAgent, &storedToken.IPAddress,
	)

	if err == sql.ErrNoRows {
		// Check if this selector was previously valid (potential theft)
		var wasRevoked bool
		ts.db.QueryRowContext(ctx, 
			"SELECT revoked FROM remember_tokens WHERE selector = $1", 
			selector).Scan(&wasRevoked)

		if wasRevoked {
			logger.Error("attempted use of revoked token - possible theft",
				"selector", selector[:8]+"...",
				"ip", r.RemoteAddr,
			)
			return nil, ErrTokenCompromised
		}
		return nil, ErrInvalidToken
	}
	if err != nil {
		return nil, err
	}

	// Check expiration
	if time.Now().After(storedToken.ExpiresAt) {
		ts.revokeToken(ctx, storedToken.ID)
		return nil, ErrInvalidToken
	}

	// CRITICAL: Constant-time comparison of hashed validator
	hashedValidator := hashToken(validator)
	if subtle.ConstantTimeCompare(
		[]byte(hashedValidator), 
		[]byte(storedToken.HashedToken),
	) != 1 {
		logger.Warn("remember token validator mismatch",
			"selector", selector[:8]+"...",
			"user_id", storedToken.UserID,
			"ip", r.RemoteAddr,
		)
		return nil, ErrInvalidToken
	}

	// Anomaly detection: Check for suspicious context changes
	ts.checkAnomalies(ctx, &storedToken, r)

	result := &TokenValidationResult{
		UserID:  storedToken.UserID,
		TokenID: storedToken.ID,
	}

	// Rotate token if it's older than rotation period
	if time.Since(storedToken.LastUsedAt) > ts.rotationPeriod {
		newToken, err := ts.rotateToken(ctx, storedToken.ID, storedToken.UserID, r)
		if err != nil {
			logger.Error("token rotation failed", "error", err)
			// Continue with existing token on rotation failure
		} else {
			result.NeedsRotation = true
			result.NewToken = newToken
		}
	} else {
		// Update last used timestamp
		ts.db.ExecContext(ctx,
			"UPDATE remember_tokens SET last_used_at = NOW() WHERE id = $1",
			storedToken.ID,
		)
	}

	logger.Info("remember token validated",
		"user_id", storedToken.UserID,
		"token_id", storedToken.ID,
		"rotated", result.NeedsRotation,
	)

	return result, nil
}

// rotateToken creates a new token and invalidates the old one
func (ts *TokenService) rotateToken(ctx context.Context, oldTokenID, userID int, r *http.Request) (string, error) {
	tx, err := ts.db.BeginTx(ctx, nil)
	if err != nil {
		return "", err
	}
	defer tx.Rollback()

	// Revoke old token
	_, err = tx.ExecContext(ctx,
		"UPDATE remember_tokens SET revoked = TRUE, revoked_at = NOW() WHERE id = $1",
		oldTokenID,
	)
	if err != nil {
		return "", err
	}

	// Generate new token
	selector, _ := generateSecureToken(16)
	validator, _ := generateSecureToken(32)
	hashedValidator := hashToken(validator)

	_, err = tx.ExecContext(ctx, `
		INSERT INTO remember_tokens 
		(user_id, selector, hashed_token, expires_at, created_at, last_used_at, user_agent, ip_address)
		VALUES ($1, $2, $3, $4, NOW(), NOW(), $5, $6)`,
		userID, selector, hashedValidator,
		time.Now().Add(ts.maxTokenAge),
		r.UserAgent(), r.RemoteAddr,
	)
	if err != nil {
		return "", err
	}

	if err := tx.Commit(); err != nil {
		return "", err
	}

	return selector + ":" + validator, nil
}

// RevokeAllUserTokens invalidates all remember-me tokens for a user
// Call this on: password change, explicit logout, security concern
func (ts *TokenService) RevokeAllUserTokens(ctx context.Context, userID int, reason string) error {
	result, err := ts.db.ExecContext(ctx, `
		UPDATE remember_tokens 
		SET revoked = TRUE, revoked_at = NOW(), revoke_reason = $2
		WHERE user_id = $1 AND revoked = FALSE`,
		userID, reason,
	)
	if err != nil {
		return err
	}

	rowsAffected, _ := result.RowsAffected()
	logger.Info("revoked all user tokens",
		"user_id", userID,
		"reason", reason,
		"tokens_revoked", rowsAffected,
	)

	return nil
}

// ChangePassword handles password change with token invalidation
func (ts *TokenService) ChangePassword(ctx context.Context, userID int, newPasswordHash string) error {
	tx, err := ts.db.BeginTx(ctx, nil)
	if err != nil {
		return err
	}
	defer tx.Rollback()

	// Update password
	_, err = tx.ExecContext(ctx,
		"UPDATE users SET password_hash = $1, password_changed_at = NOW() WHERE id = $2",
		newPasswordHash, userID,
	)
	if err != nil {
		return err
	}

	// CRITICAL: Invalidate ALL remember-me tokens
	_, err = tx.ExecContext(ctx, `
		UPDATE remember_tokens 
		SET revoked = TRUE, revoked_at = NOW(), revoke_reason = 'password_change'
		WHERE user_id = $1 AND revoked = FALSE`,
		userID,
	)
	if err != nil {
		return err
	}

	if err := tx.Commit(); err != nil {
		return err
	}

	logger.Info("password changed, all tokens revoked", "user_id", userID)
	return nil
}

func (ts *TokenService) checkAnomalies(ctx context.Context, token *struct {
	ID          int
	UserID      int
	HashedToken string
	ExpiresAt   time.Time
	LastUsedAt  time.Time
	UserAgent   string
	IPAddress   string
}, r *http.Request) {
	// Detect suspicious behavior
	if token.UserAgent != r.UserAgent() {
		logger.Warn("user agent changed for remember token",
			"user_id", token.UserID,
			"original_ua", token.UserAgent,
			"new_ua", r.UserAgent(),
		)
	}
	// Could add IP geolocation checks, impossible travel detection, etc.
}

func (ts *TokenService) revokeToken(ctx context.Context, tokenID int) {
	ts.db.ExecContext(ctx,
		"UPDATE remember_tokens SET revoked = TRUE, revoked_at = NOW() WHERE id = $1",
		tokenID,
	)
}

func generateSecureToken(length int) (string, error) {
	bytes := make([]byte, length)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes), nil
}

func hashToken(token string) string {
	hash := sha256.Sum256([]byte(token))
	return hex.EncodeToString(hash[:])
}

// Middleware that handles remember-me authentication
func (ts *TokenService) RememberMeMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Check if already authenticated via session
		if sessionUserID := r.Context().Value("user_id"); sessionUserID != nil {
			next.ServeHTTP(w, r)
			return
		}

		cookie, err := r.Cookie("remember_token")
		if err != nil {
			next.ServeHTTP(w, r)
			return
		}

		result, err := ts.ValidateAndRotateToken(r.Context(), cookie.Value, r)
		if err != nil {
			// Clear invalid cookie
			http.SetCookie(w, &http.Cookie{
				Name:     "remember_token",
				Value:    "",
				MaxAge:   -1,
				Path:     "/",
				HttpOnly: true,
				Secure:   true,
			})

			if errors.Is(err, ErrTokenCompromised) {
				// Potential token theft - force re-authentication
				http.Redirect(w, r, "/login?security_alert=1", http.StatusFound)
				return
			}

			next.ServeHTTP(w, r)
			return
		}

		// Set rotated token if needed
		if result.NeedsRotation {
			http.SetCookie(w, &http.Cookie{
				Name:     "remember_token",
				Value:    result.NewToken,
				Expires:  time.Now().Add(ts.maxTokenAge),
				Path:     "/",
				HttpOnly: true,
				Secure:   true,
				SameSite: http.SameSiteStrictMode,
			})
		}

		// Add user to context
		ctx := context.WithValue(r.Context(), "user_id", result.UserID)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}
```

**Defense in Depth Layers**:

1. **Cryptographic Security**:
```go
// Unpredictable tokens using crypto/rand
bytes := make([]byte, length)
crypto_rand.Read(bytes)

// SHA-256 hashing of validator before storage
hash := sha256.Sum256([]byte(validator))

// Constant-time comparison prevents timing attacks
subtle.ConstantTimeCompare([]byte(hash1), []byte(hash2))
```

2. **Token Lifecycle Management**:
```go
// Automatic rotation after 24 hours of use
if time.Since(token.LastUsedAt) > ts.rotationPeriod {
    newToken, _ := ts.rotateToken(ctx, token.ID, token.UserID, r)
}

// Mandatory invalidation on security events
ts.RevokeAllUserTokens(ctx, userID, "password_change")
ts.RevokeAllUserTokens(ctx, userID, "security_alert")
ts.RevokeAllUserTokens(ctx, userID, "user_logout_all")
```

3. **Anomaly Detection**:
```go
// Track and alert on context changes
if token.UserAgent != r.UserAgent() {
    logger.Warn("user agent changed", ...)
    // Could trigger step-up authentication
}

// Detect reuse of revoked tokens (theft indicator)
if wasRevoked {
    logger.Error("attempted use of revoked token - possible theft")
    return nil, ErrTokenCompromised
}
```

**Additional Protections**:
- **Database schema** includes `revoked`, `revoked_at`, `revoke_reason` for audit trail
- **Maximum tokens per user** prevents token accumulation attacks
- **Structured logging** enables security monitoring and alerting
- **Graceful degradation** on rotation failure (continues with existing token)
- **FOR UPDATE** row locking prevents race conditions during rotation
- **Clear invalid cookies** immediately on validation failure
- **Step-up authentication** can be triggered for high-risk anomalies

Password reset is a critical security feature that attackers frequently target. A common vulnerability is creating reset tokens that never expire, allowing attackers to use stolen or leaked tokens indefinitely.

**VULNERABLE CODE**:

```php
<?php
// vulnerable_password_reset.php

class PasswordResetController {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    // VULNERABLE: Token never expires
    public function createResetToken($email) {
        $token = bin2hex(random_bytes(32));

        // No expiration time stored!
        $stmt = $this->pdo->prepare(
            "INSERT INTO password_resets (email, token) VALUES (?, ?)"
        );
        $stmt->execute([$email, $token]);

        $resetLink = "https://example.com/reset?token=" . $token;
        mail($email, "Password Reset", "Click here: $resetLink");

        return true;
    }

    // VULNERABLE: No expiration check
    public function resetPassword($token, $newPassword) {
        $stmt = $this->pdo->prepare(
            "SELECT email FROM password_resets WHERE token = ?"
        );
        $stmt->execute([$token]);
        $result = $stmt->fetch();

        if ($result) {
            // Password is reset - token works forever!
            $hashedPassword = password_hash($newPassword, PASSWORD_DEFAULT);
            $updateStmt = $this->pdo->prepare(
                "UPDATE users SET password = ? WHERE email = ?"
            );
            $updateStmt->execute([$hashedPassword, $result['email']]);

            // Token is never invalidated, can be reused!
            return true;
        }
        return false;
    }
}
?>
```

**Attack Scenario**:
```text
1. Attacker gains access to victim's old emails (email breach, phishing)
2. Finds password reset link from 6 months ago
3. Token still works - attacker resets password and takes over account
4. Victim has no idea their account was compromised
```

**Why This Is Dangerous**:
- Tokens remain valid indefinitely - old leaked tokens work forever
- No token invalidation after use - same token can reset password multiple times
- No tracking of token age - impossible to detect suspicious old token usage
- Email account compromise = permanent account takeover vector

**SECURE VERSION**:

```php
<?php
// secure_password_reset.php

class SecurePasswordResetController {
    private $pdo;
    private const TOKEN_EXPIRY_MINUTES = 15; // Strict expiration

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    public function createResetToken($email) {
        // Verify user exists first
        $userStmt = $this->pdo->prepare("SELECT id FROM users WHERE email = ?");
        $userStmt->execute([$email]);
        if (!$userStmt->fetch()) {
            // Return true anyway to prevent email enumeration
            return true;
        }

        // Invalidate any existing tokens for this email
        $deleteStmt = $this->pdo->prepare(
            "DELETE FROM password_resets WHERE email = ?"
        );
        $deleteStmt->execute([$email]);

        // Generate cryptographically secure token
        $token = bin2hex(random_bytes(32));
        $hashedToken = hash('sha256', $token); // Store hashed
        $expiresAt = date('Y-m-d H:i:s', strtotime('+' . self::TOKEN_EXPIRY_MINUTES . ' minutes'));

        $stmt = $this->pdo->prepare(
            "INSERT INTO password_resets (email, token_hash, expires_at, created_at) 
             VALUES (?, ?, ?, NOW())"
        );
        $stmt->execute([$email, $hashedToken, $expiresAt]);

        // Log the reset request
        error_log("Password reset requested for: " . hash('sha256', $email));

        $resetLink = "https://example.com/reset?token=" . $token;
        // Use proper email library in production
        mail($email, "Password Reset (expires in 15 min)", 
             "Click here within 15 minutes: $resetLink");

        return true;
    }

    public function resetPassword($token, $newPassword) {
        // Hash the provided token to compare
        $hashedToken = hash('sha256', $token);

        // Check token exists AND is not expired
        $stmt = $this->pdo->prepare(
            "SELECT email, expires_at FROM password_resets 
             WHERE token_hash = ? AND expires_at > NOW()"
        );
        $stmt->execute([$hashedToken]);
        $result = $stmt->fetch();

        if (!$result) {
            error_log("Invalid or expired reset token attempted");
            return ['success' => false, 'error' => 'Invalid or expired token'];
        }

        // Validate password strength
        if (strlen($newPassword) < 12) {
            return ['success' => false, 'error' => 'Password must be at least 12 characters'];
        }

        // Update password with strong hashing
        $hashedPassword = password_hash($newPassword, PASSWORD_ARGON2ID);
        $updateStmt = $this->pdo->prepare(
            "UPDATE users SET password = ?, password_changed_at = NOW() WHERE email = ?"
        );
        $updateStmt->execute([$hashedPassword, $result['email']]);

        // CRITICAL: Invalidate token immediately after use
        $deleteStmt = $this->pdo->prepare(
            "DELETE FROM password_resets WHERE email = ?"
        );
        $deleteStmt->execute([$result['email']]);

        // Invalidate all existing sessions
        $sessionStmt = $this->pdo->prepare(
            "DELETE FROM user_sessions WHERE user_email = ?"
        );
        $sessionStmt->execute([$result['email']]);

        error_log("Password successfully reset for user");

        return ['success' => true];
    }
}
?>
```

**Key Security Controls**:
- **Token expiration (15 minutes)**: Severely limits the attack window for stolen tokens
- **Single-use tokens**: Deleted immediately after successful reset, preventing replay attacks
- **Token hashing**: Raw tokens never stored in database, protecting against DB breaches
- **Session invalidation**: All existing sessions terminated, forcing re-authentication everywhere

Excellent security thinking! Rate limiting and preventing email enumeration are critical for a production password reset system. Let me show you a comprehensive implementation.

**PRODUCTION PATTERN**:

```php
<?php
// production_password_reset.php

class ProductionPasswordResetService {
    private $pdo;
    private $redis;
    private $mailer;
    private $logger;

    private const TOKEN_EXPIRY_MINUTES = 15;
    private const MAX_REQUESTS_PER_IP_HOUR = 5;
    private const MAX_REQUESTS_PER_EMAIL_HOUR = 3;
    private const LOCKOUT_MINUTES = 60;
    private const MAX_FAILED_ATTEMPTS = 5;

    public function __construct($pdo, $redis, $mailer, $logger) {
        $this->pdo = $pdo;
        $this->redis = $redis;
        $this->mailer = $mailer;
        $this->logger = $logger;
    }

    public function requestPasswordReset($email, $ipAddress, $userAgent) {
        // Normalize email
        $email = strtolower(trim($email));

        // Rate limiting check (before any database operations)
        $rateLimitResult = $this->checkRateLimits($email, $ipAddress);
        if (!$rateLimitResult['allowed']) {
            $this->logger->warning('Rate limit exceeded', [
                'ip' => $ipAddress,
                'email_hash' => hash('sha256', $email),
                'reason' => $rateLimitResult['reason']
            ]);

            // CRITICAL: Same response regardless of rate limit reason
            // Prevents attackers from learning about rate limit thresholds
            return $this->genericSuccessResponse();
        }

        // Check if user exists (but don't reveal this to the user)
        $user = $this->getUserByEmail($email);

        if ($user) {
            // User exists - generate real token
            $this->invalidateExistingTokens($email);
            $token = $this->generateSecureToken();
            $this->storeToken($email, $token, $ipAddress, $userAgent);
            $this->sendResetEmail($email, $token, $user['name']);

            $this->logger->info('Password reset token generated', [
                'user_id' => $user['id'],
                'ip' => $ipAddress
            ]);
        } else {
            // User doesn't exist - log but don't reveal
            $this->logger->info('Password reset attempted for non-existent email', [
                'email_hash' => hash('sha256', $email),
                'ip' => $ipAddress
            ]);
        }

        // Increment rate limit counters regardless of user existence
        $this->incrementRateLimitCounters($email, $ipAddress);

        // CRITICAL: Always same response and timing to prevent enumeration
        usleep(random_int(100000, 300000)); // Random delay 100-300ms
        return $this->genericSuccessResponse();
    }

    private function checkRateLimits($email, $ipAddress) {
        $emailKey = "reset_limit:email:" . hash('sha256', $email);
        $ipKey = "reset_limit:ip:" . $ipAddress;

        $emailCount = (int)$this->redis->get($emailKey) ?? 0;
        $ipCount = (int)$this->redis->get($ipKey) ?? 0;

        if ($emailCount >= self::MAX_REQUESTS_PER_EMAIL_HOUR) {
            return ['allowed' => false, 'reason' => 'email_limit'];
        }

        if ($ipCount >= self::MAX_REQUESTS_PER_IP_HOUR) {
            return ['allowed' => false, 'reason' => 'ip_limit'];
        }

        // Check for suspicious patterns (same IP, many different emails)
        $ipEmailsKey = "reset_emails:ip:" . $ipAddress;
        $emailsFromIp = $this->redis->scard($ipEmailsKey) ?? 0;
        if ($emailsFromIp >= 10) {
            return ['allowed' => false, 'reason' => 'enumeration_suspected'];
        }

        return ['allowed' => true];
    }

    private function incrementRateLimitCounters($email, $ipAddress) {
        $emailKey = "reset_limit:email:" . hash('sha256', $email);
        $ipKey = "reset_limit:ip:" . $ipAddress;
        $ipEmailsKey = "reset_emails:ip:" . $ipAddress;

        $this->redis->incr($emailKey);
        $this->redis->expire($emailKey, 3600); // 1 hour

        $this->redis->incr($ipKey);
        $this->redis->expire($ipKey, 3600);

        $this->redis->sadd($ipEmailsKey, hash('sha256', $email));
        $this->redis->expire($ipEmailsKey, 3600);
    }

    private function generateSecureToken() {
        return bin2hex(random_bytes(32));
    }

    private function storeToken($email, $token, $ipAddress, $userAgent) {
        $hashedToken = hash('sha256', $token);
        $expiresAt = date('Y-m-d H:i:s', 
            strtotime('+' . self::TOKEN_EXPIRY_MINUTES . ' minutes'));

        $stmt = $this->pdo->prepare(
            "INSERT INTO password_resets 
             (email, token_hash, expires_at, created_at, request_ip, user_agent) 
             VALUES (?, ?, ?, NOW(), ?, ?)"
        );
        $stmt->execute([$email, $hashedToken, $expiresAt, $ipAddress, $userAgent]);
    }

    public function resetPassword($token, $newPassword, $ipAddress) {
        $hashedToken = hash('sha256', $token);

        // Check for token brute force attempts
        $bruteForceKey = "reset_brute:ip:" . $ipAddress;
        $attempts = (int)$this->redis->get($bruteForceKey) ?? 0;

        if ($attempts >= self::MAX_FAILED_ATTEMPTS) {
            $this->logger->warning('Reset token brute force detected', [
                'ip' => $ipAddress
            ]);
            return [
                'success' => false, 
                'error' => 'Too many attempts. Please try again later.'
            ];
        }

        // Validate token
        $stmt = $this->pdo->prepare(
            "SELECT pr.email, pr.expires_at, pr.request_ip, u.id as user_id
             FROM password_resets pr
             JOIN users u ON pr.email = u.email
             WHERE pr.token_hash = ? AND pr.expires_at > NOW() AND pr.used_at IS NULL"
        );
        $stmt->execute([$hashedToken]);
        $result = $stmt->fetch();

        if (!$result) {
            // Invalid token - increment brute force counter
            $this->redis->incr($bruteForceKey);
            $this->redis->expire($bruteForceKey, self::LOCKOUT_MINUTES * 60);

            $this->logger->warning('Invalid reset token attempted', [
                'ip' => $ipAddress,
                'attempts' => $attempts + 1
            ]);

            return [
                'success' => false,
                'error' => 'Invalid or expired reset link. Please request a new one.'
            ];
        }

        // Validate password strength
        $passwordValidation = $this->validatePasswordStrength($newPassword);
        if (!$passwordValidation['valid']) {
            return ['success' => false, 'error' => $passwordValidation['error']];
        }

        // Check password not in breach database (using k-anonymity)
        if ($this->isPasswordPwned($newPassword)) {
            return [
                'success' => false,
                'error' => 'This password has been exposed in data breaches. Please choose another.'
            ];
        }

        try {
            $this->pdo->beginTransaction();

            // Update password
            $hashedPassword = password_hash($newPassword, PASSWORD_ARGON2ID, [
                'memory_cost' => 65536,
                'time_cost' => 4,
                'threads' => 3
            ]);

            $updateStmt = $this->pdo->prepare(
                "UPDATE users SET 
                 password = ?, 
                 password_changed_at = NOW(),
                 failed_login_attempts = 0
                 WHERE id = ?"
            );
            $updateStmt->execute([$hashedPassword, $result['user_id']]);

            // Mark token as used (don't delete - keep for audit)
            $tokenStmt = $this->pdo->prepare(
                "UPDATE password_resets SET used_at = NOW(), used_ip = ? 
                 WHERE token_hash = ?"
            );
            $tokenStmt->execute([$ipAddress, $hashedToken]);

            // Invalidate ALL user sessions
            $sessionStmt = $this->pdo->prepare(
                "DELETE FROM user_sessions WHERE user_id = ?"
            );
            $sessionStmt->execute([$result['user_id']]);

            // Record in audit log
            $auditStmt = $this->pdo->prepare(
                "INSERT INTO security_audit_log 
                 (user_id, action, ip_address, details, created_at) 
                 VALUES (?, 'password_reset_completed', ?, ?, NOW())"
            );
            $auditStmt->execute([
                $result['user_id'],
                $ipAddress,
                json_encode(['original_request_ip' => $result['request_ip']])
            ]);

            $this->pdo->commit();

            // Send notification email
            $this->sendPasswordChangedNotification($result['email'], $ipAddress);

            // Clear brute force counter on success
            $this->redis->del($bruteForceKey);

            $this->logger->info('Password reset completed', [
                'user_id' => $result['user_id'],
                'ip' => $ipAddress
            ]);

            return ['success' => true];

        } catch (Exception $e) {
            $this->pdo->rollBack();
            $this->logger->error('Password reset failed', [
                'error' => $e->getMessage(),
                'ip' => $ipAddress
            ]);
            return ['success' => false, 'error' => 'An error occurred. Please try again.'];
        }
    }

    private function validatePasswordStrength($password) {
        if (strlen($password) < 12) {
            return ['valid' => false, 'error' => 'Password must be at least 12 characters'];
        }
        if (!preg_match('/[A-Z]/', $password)) {
            return ['valid' => false, 'error' => 'Password must contain uppercase letter'];
        }
        if (!preg_match('/[a-z]/', $password)) {
            return ['valid' => false, 'error' => 'Password must contain lowercase letter'];
        }
        if (!preg_match('/[0-9]/', $password)) {
            return ['valid' => false, 'error' => 'Password must contain a number'];
        }
        return ['valid' => true];
    }

    private function isPasswordPwned($password) {
        // Using Have I Been Pwned API with k-anonymity
        $sha1 = strtoupper(sha1($password));
        $prefix = substr($sha1, 0, 5);
        $suffix = substr($sha1, 5);

        $ch = curl_init("https://api.pwnedpasswords.com/range/" . $prefix);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_HTTPHEADER, ['Add-Padding: true']);
        $response = curl_exec($ch);
        curl_close($ch);

        return strpos($response, $suffix) !== false;
    }

    private function genericSuccessResponse() {
        return [
            'success' => true,
            'message' => 'If an account exists with this email, you will receive reset instructions.'
        ];
    }

    private function getUserByEmail($email) {
        $stmt = $this->pdo->prepare("SELECT id, name, email FROM users WHERE email = ?");
        $stmt->execute([$email]);
        return $stmt->fetch();
    }

    private function invalidateExistingTokens($email) {
        $stmt = $this->pdo->prepare(
            "UPDATE password_resets SET expires_at = NOW() WHERE email = ? AND used_at IS NULL"
        );
        $stmt->execute([$email]);
    }

    private function sendResetEmail($email, $token, $name) {
        $resetLink = "https://example.com/reset-password?token=" . $token;
        $this->mailer->send($email, 'Password Reset Request', 
            "Hi $name,\n\nClick here to reset your password (expires in 15 minutes): $resetLink\n\n" .
            "If you didn't request this, please ignore this email.");
    }

    private function sendPasswordChangedNotification($email, $ipAddress) {
        $this->mailer->send($email, 'Your Password Was Changed',
            "Your password was just changed from IP: $ipAddress\n\n" .
            "If this wasn't you, contact support immediately.");
    }
}
