Storing predictable user identifiers in cookies for 'remember me' functionality is extremely dangerous. This pattern was exploited in numerous authentication bypass vulnerabilities, including issues similar to the Atlassian Confluence bypass where attackers could gain unauthorized access by manipulating authentication tokens.

**VULNERABLE CODE**:

```csharp
using System;
using System.Web;
using System.Web.Mvc;
using System.Data.SqlClient;

namespace VulnerableApp.Controllers
{
    public class AuthController : Controller
    {
        private readonly string _connectionString = "Server=localhost;Database=UserDB;Integrated Security=true;";

        [HttpPost]
        public ActionResult Login(string username, string password, bool rememberMe)
        {
            // VULNERABLE: Predictable remember-me token
            using (var conn = new SqlConnection(_connectionString))
            {
                conn.Open();
                var cmd = new SqlCommand(
                    "SELECT Id, PasswordHash FROM Users WHERE Username = @username", conn);
                cmd.Parameters.AddWithValue("@username", username);

                using (var reader = cmd.ExecuteReader())
                {
                    if (reader.Read())
                    {
                        int userId = reader.GetInt32(0);
                        string storedHash = reader.GetString(1);

                        if (VerifyPassword(password, storedHash))
                        {
                            Session["UserId"] = userId;

                            if (rememberMe)
                            {
                                // VULNERABLE: Predictable token based on user ID
                                var cookie = new HttpCookie("RememberMe")
                                {
                                    Value = userId.ToString(), // Just the user ID!
                                    Expires = DateTime.Now.AddDays(30),
                                    HttpOnly = false // Can be stolen via XSS
                                };
                                Response.Cookies.Add(cookie);
                            }
                            return RedirectToAction("Dashboard", "Home");
                        }
                    }
                }
            }
            return View("Login", new { Error = "Invalid credentials" });
        }

        public ActionResult AutoLogin()
        {
            // VULNERABLE: Trusts cookie value directly
            var cookie = Request.Cookies["RememberMe"];
            if (cookie != null && int.TryParse(cookie.Value, out int userId))
            {
                Session["UserId"] = userId; // Direct trust!
                return RedirectToAction("Dashboard", "Home");
            }
            return RedirectToAction("Login");
        }

        private bool VerifyPassword(string password, string storedHash)
        {
            // Password verification logic
            return BCrypt.Net.BCrypt.Verify(password, storedHash);
        }
    }
}
```

**Attack Payload**:
```text
Cookie: RememberMe=1
```
An attacker simply sets the cookie to any user ID (e.g., admin user ID = 1) to gain access to that account.

**Why This Is Dangerous**:
- **Predictable tokens**: Using sequential user IDs allows attackers to enumerate and impersonate any user
- **No server-side validation**: The token isn't verified against a secure server-side store
- **No expiration enforcement**: Token validity isn't checked beyond cookie expiration
- **Missing HttpOnly/Secure flags**: Token can be stolen via XSS or MITM attacks
- **Persists after password change**: User cannot invalidate compromised tokens

**SECURE VERSION**:

```csharp
using System;
using System.Web;
using System.Web.Mvc;
using System.Data.SqlClient;
using System.Security.Cryptography;
using System.Text;

namespace SecureApp.Controllers
{
    public class AuthController : Controller
    {
        private readonly string _connectionString = "Server=localhost;Database=UserDB;Integrated Security=true;";
        private const int TokenExpirationDays = 30;

        [HttpPost]
        public ActionResult Login(string username, string password, bool rememberMe)
        {
            using (var conn = new SqlConnection(_connectionString))
            {
                conn.Open();
                var cmd = new SqlCommand(
                    "SELECT Id, PasswordHash FROM Users WHERE Username = @username", conn);
                cmd.Parameters.AddWithValue("@username", username);

                using (var reader = cmd.ExecuteReader())
                {
                    if (reader.Read())
                    {
                        int userId = reader.GetInt32(0);
                        string storedHash = reader.GetString(1);

                        if (BCrypt.Net.BCrypt.Verify(password, storedHash))
                        {
                            Session["UserId"] = userId;

                            if (rememberMe)
                            {
                                // SECURE: Generate cryptographically random token
                                string selector = GenerateSecureToken(12);
                                string validator = GenerateSecureToken(32);
                                string validatorHash = HashToken(validator);

                                // Store hashed validator in database
                                StoreRememberToken(userId, selector, validatorHash, 
                                    DateTime.UtcNow.AddDays(TokenExpirationDays));

                                // Send selector:validator to client
                                var cookie = new HttpCookie("RememberMe")
                                {
                                    Value = $"{selector}:{validator}",
                                    Expires = DateTime.Now.AddDays(TokenExpirationDays),
                                    HttpOnly = true,  // Prevent XSS theft
                                    Secure = true,    // HTTPS only
                                    SameSite = SameSiteMode.Strict // CSRF protection
                                };
                                Response.Cookies.Add(cookie);
                            }
                            return RedirectToAction("Dashboard", "Home");
                        }
                    }
                }
            }
            return View("Login", new { Error = "Invalid credentials" });
        }

        private string GenerateSecureToken(int length)
        {
            byte[] tokenBytes = new byte[length];
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(tokenBytes);
            }
            return Convert.ToBase64String(tokenBytes)
                .Replace("+", "-").Replace("/", "_").TrimEnd('=');
        }

        private string HashToken(string token)
        {
            using (var sha256 = SHA256.Create())
            {
                byte[] bytes = sha256.ComputeHash(Encoding.UTF8.GetBytes(token));
                return Convert.ToBase64String(bytes);
            }
        }

        private void StoreRememberToken(int userId, string selector, 
            string validatorHash, DateTime expiry)
        {
            using (var conn = new SqlConnection(_connectionString))
            {
                conn.Open();
                var cmd = new SqlCommand(@"
                    INSERT INTO RememberTokens (UserId, Selector, ValidatorHash, ExpiresAt, CreatedAt)
                    VALUES (@userId, @selector, @validatorHash, @expiry, @created)", conn);
                cmd.Parameters.AddWithValue("@userId", userId);
                cmd.Parameters.AddWithValue("@selector", selector);
                cmd.Parameters.AddWithValue("@validatorHash", validatorHash);
                cmd.Parameters.AddWithValue("@expiry", expiry);
                cmd.Parameters.AddWithValue("@created", DateTime.UtcNow);
                cmd.ExecuteNonQuery();
            }
        }
    }
}
```

**Key Security Controls**:
- **Cryptographically random tokens**: Uses `RandomNumberGenerator` to create unpredictable selectors and validators
- **Split-token design**: Selector finds the record, hashed validator proves possession - prevents timing attacks
- **Server-side validation**: Token must exist in database with matching hash
- **Secure cookie attributes**: HttpOnly, Secure, and SameSite flags prevent common attacks
- **Expiration enforcement**: Server-side expiration check, not just cookie expiry

Excellent questions! Token invalidation and replay protection are critical for production-ready remember-me implementations. The 2023-2024 wave of authentication bypasses demonstrated that many organizations fail to properly invalidate persistent tokens after security-critical events.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Web;
using System.Web.Mvc;
using System.Data.SqlClient;
using System.Security.Cryptography;
using System.Text;
using NLog;

namespace SecureApp.Controllers
{
    public class SecureAuthController : Controller
    {
        private static readonly Logger _logger = LogManager.GetCurrentClassLogger();
        private readonly string _connectionString;
        private const int TokenExpirationDays = 30;
        private const int MaxTokensPerUser = 5;
        private const int TokenRotationMinutes = 15;

        public SecureAuthController()
        {
            _connectionString = System.Configuration.ConfigurationManager
                .ConnectionStrings["UserDB"].ConnectionString;
        }

        public ActionResult AutoLogin()
        {
            var cookie = Request.Cookies["RememberMe"];
            if (cookie == null || string.IsNullOrEmpty(cookie.Value))
            {
                return RedirectToAction("Login");
            }

            var parts = cookie.Value.Split(':');
            if (parts.Length != 2)
            {
                ClearRememberCookie();
                _logger.Warn($"Malformed remember token from IP: {GetClientIP()}");
                return RedirectToAction("Login");
            }

            string selector = parts[0];
            string validator = parts[1];

            using (var conn = new SqlConnection(_connectionString))
            {
                conn.Open();
                using (var transaction = conn.BeginTransaction())
                {
                    try
                    {
                        // Fetch token by selector
                        var cmd = new SqlCommand(@"
                            SELECT t.Id, t.UserId, t.ValidatorHash, t.ExpiresAt, 
                                   t.LastUsedAt, t.UserAgent, t.IpAddress,
                                   u.PasswordChangedAt, u.TokensInvalidatedAt
                            FROM RememberTokens t
                            INNER JOIN Users u ON t.UserId = u.Id
                            WHERE t.Selector = @selector AND t.IsRevoked = 0", conn, transaction);
                        cmd.Parameters.AddWithValue("@selector", selector);

                        using (var reader = cmd.ExecuteReader())
                        {
                            if (!reader.Read())
                            {
                                reader.Close();
                                _logger.Warn($"Unknown selector attempted from IP: {GetClientIP()}");
                                ClearRememberCookie();
                                return RedirectToAction("Login");
                            }

                            int tokenId = reader.GetInt32(0);
                            int userId = reader.GetInt32(1);
                            string storedHash = reader.GetString(2);
                            DateTime expiresAt = reader.GetDateTime(3);
                            DateTime? lastUsedAt = reader.IsDBNull(4) ? null : (DateTime?)reader.GetDateTime(4);
                            string storedUserAgent = reader.IsDBNull(5) ? null : reader.GetString(5);
                            string storedIpAddress = reader.IsDBNull(6) ? null : reader.GetString(6);
                            DateTime? passwordChangedAt = reader.IsDBNull(7) ? null : (DateTime?)reader.GetDateTime(7);
                            DateTime? tokensInvalidatedAt = reader.IsDBNull(8) ? null : (DateTime?)reader.GetDateTime(8);
                            reader.Close();

                            // Check expiration
                            if (DateTime.UtcNow > expiresAt)
                            {
                                RevokeToken(conn, transaction, tokenId, "expired");
                                transaction.Commit();
                                ClearRememberCookie();
                                return RedirectToAction("Login");
                            }

                            // Check if password was changed after token creation
                            var tokenCreatedCmd = new SqlCommand(
                                "SELECT CreatedAt FROM RememberTokens WHERE Id = @id", conn, transaction);
                            tokenCreatedCmd.Parameters.AddWithValue("@id", tokenId);
                            DateTime tokenCreatedAt = (DateTime)tokenCreatedCmd.ExecuteScalar();

                            if (passwordChangedAt.HasValue && passwordChangedAt > tokenCreatedAt)
                            {
                                RevokeToken(conn, transaction, tokenId, "password_changed");
                                transaction.Commit();
                                ClearRememberCookie();
                                _logger.Info($"Token rejected: password changed after token issue. UserId: {userId}");
                                return RedirectToAction("Login");
                            }

                            // Check global token invalidation (logout from all devices)
                            if (tokensInvalidatedAt.HasValue && tokensInvalidatedAt > tokenCreatedAt)
                            {
                                RevokeToken(conn, transaction, tokenId, "global_logout");
                                transaction.Commit();
                                ClearRememberCookie();
                                return RedirectToAction("Login");
                            }

                            // Constant-time comparison to prevent timing attacks
                            string providedHash = HashToken(validator);
                            if (!ConstantTimeEquals(storedHash, providedHash))
                            {
                                // Possible token theft - validator mismatch with valid selector
                                RevokeAllUserTokens(conn, transaction, userId, "possible_theft");
                                transaction.Commit();
                                ClearRememberCookie();
                                _logger.Error($"SECURITY: Possible token theft detected! UserId: {userId}, IP: {GetClientIP()}");
                                AlertSecurityTeam(userId, "Remember-me token theft detected");
                                return RedirectToAction("Login", new { SecurityAlert = true });
                            }

                            // Anomaly detection - different fingerprint
                            if (!string.IsNullOrEmpty(storedUserAgent) && 
                                storedUserAgent != Request.UserAgent)
                            {
                                _logger.Warn($"User agent change detected for UserId: {userId}. " +
                                           $"Original: {storedUserAgent}, Current: {Request.UserAgent}");
                                // Optionally require re-authentication for sensitive changes
                            }

                            // SUCCESS - Token is valid
                            Session["UserId"] = userId;
                            Session["AuthMethod"] = "remember_token";
                            Session["RequireReauthForSensitive"] = true; // Flag for sensitive operations

                            // Token rotation - issue new token after period
                            if (lastUsedAt.HasValue && 
                                (DateTime.UtcNow - lastUsedAt.Value).TotalMinutes > TokenRotationMinutes)
                            {
                                // Rotate token
                                string newSelector = GenerateSecureToken(12);
                                string newValidator = GenerateSecureToken(32);
                                string newValidatorHash = HashToken(newValidator);

                                // Revoke old token
                                RevokeToken(conn, transaction, tokenId, "rotated");

                                // Issue new token
                                var insertCmd = new SqlCommand(@"
                                    INSERT INTO RememberTokens 
                                    (UserId, Selector, ValidatorHash, ExpiresAt, CreatedAt, 
                                     LastUsedAt, UserAgent, IpAddress, IsRevoked)
                                    VALUES (@userId, @selector, @hash, @expires, @created, 
                                            @lastUsed, @userAgent, @ip, 0)", conn, transaction);
                                insertCmd.Parameters.AddWithValue("@userId", userId);
                                insertCmd.Parameters.AddWithValue("@selector", newSelector);
                                insertCmd.Parameters.AddWithValue("@hash", newValidatorHash);
                                insertCmd.Parameters.AddWithValue("@expires", DateTime.UtcNow.AddDays(TokenExpirationDays));
                                insertCmd.Parameters.AddWithValue("@created", DateTime.UtcNow);
                                insertCmd.Parameters.AddWithValue("@lastUsed", DateTime.UtcNow);
                                insertCmd.Parameters.AddWithValue("@userAgent", Request.UserAgent ?? (object)DBNull.Value);
                                insertCmd.Parameters.AddWithValue("@ip", GetClientIP());
                                insertCmd.ExecuteNonQuery();

                                // Set new cookie
                                var newCookie = new HttpCookie("RememberMe")
                                {
                                    Value = $"{newSelector}:{newValidator}",
                                    Expires = DateTime.Now.AddDays(TokenExpirationDays),
                                    HttpOnly = true,
                                    Secure = true,
                                    SameSite = SameSiteMode.Strict
                                };
                                Response.Cookies.Add(newCookie);

                                _logger.Info($"Token rotated for UserId: {userId}");
                            }
                            else
                            {
                                // Update last used time
                                var updateCmd = new SqlCommand(
                                    "UPDATE RememberTokens SET LastUsedAt = @now WHERE Id = @id", 
                                    conn, transaction);
                                updateCmd.Parameters.AddWithValue("@now", DateTime.UtcNow);
                                updateCmd.Parameters.AddWithValue("@id", tokenId);
                                updateCmd.ExecuteNonQuery();
                            }

                            transaction.Commit();
                            return RedirectToAction("Dashboard", "Home");
                        }
                    }
                    catch (Exception ex)
                    {
                        transaction.Rollback();
                        _logger.Error(ex, "Error during auto-login");
                        ClearRememberCookie();
                        return RedirectToAction("Login");
                    }
                }
            }
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult ChangePassword(string currentPassword, string newPassword)
        {
            int userId = (int)Session["UserId"];

            using (var conn = new SqlConnection(_connectionString))
            {
                conn.Open();
                using (var transaction = conn.BeginTransaction())
                {
                    // Verify current password and update
                    // ... password change logic ...

                    // CRITICAL: Invalidate ALL remember-me tokens
                    RevokeAllUserTokens(conn, transaction, userId, "password_change");

                    // Update password changed timestamp
                    var updateCmd = new SqlCommand(
                        "UPDATE Users SET PasswordChangedAt = @now WHERE Id = @id", 
                        conn, transaction);
                    updateCmd.Parameters.AddWithValue("@now", DateTime.UtcNow);
                    updateCmd.Parameters.AddWithValue("@id", userId);
                    updateCmd.ExecuteNonQuery();

                    transaction.Commit();
                }
            }

            _logger.Info($"Password changed and all tokens revoked for UserId: {userId}");
            return Json(new { success = true, message = "Password changed. Please log in again on other devices." });
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult LogoutAllDevices()
        {
            int userId = (int)Session["UserId"];

            using (var conn = new SqlConnection(_connectionString))
            {
                conn.Open();

                // Revoke all tokens
                var revokeCmd = new SqlCommand(@"
                    UPDATE RememberTokens 
                    SET IsRevoked = 1, RevokedAt = @now, RevokeReason = 'global_logout'
                    WHERE UserId = @userId AND IsRevoked = 0", conn);
                revokeCmd.Parameters.AddWithValue("@now", DateTime.UtcNow);
                revokeCmd.Parameters.AddWithValue("@userId", userId);
                int revokedCount = revokeCmd.ExecuteNonQuery();

                // Update global invalidation timestamp
                var updateCmd = new SqlCommand(
                    "UPDATE Users SET TokensInvalidatedAt = @now WHERE Id = @id", conn);
                updateCmd.Parameters.AddWithValue("@now", DateTime.UtcNow);
                updateCmd.Parameters.AddWithValue("@id", userId);
                updateCmd.ExecuteNonQuery();

                _logger.Info($"Global logout: {revokedCount} tokens revoked for UserId: {userId}");
            }

            ClearRememberCookie();
            Session.Abandon();
            return RedirectToAction("Login");
        }

        private void RevokeAllUserTokens(SqlConnection conn, SqlTransaction transaction, 
            int userId, string reason)
        {
            var cmd = new SqlCommand(@"
                UPDATE RememberTokens 
                SET IsRevoked = 1, RevokedAt = @now, RevokeReason = @reason
                WHERE UserId = @userId AND IsRevoked = 0", conn, transaction);
            cmd.Parameters.AddWithValue("@now", DateTime.UtcNow);
            cmd.Parameters.AddWithValue("@reason", reason);
            cmd.Parameters.AddWithValue("@userId", userId);
            cmd.ExecuteNonQuery();
        }

        private void RevokeToken(SqlConnection conn, SqlTransaction transaction, 
            int tokenId, string reason)
        {
            var cmd = new SqlCommand(@"
                UPDATE RememberTokens 
                SET IsRevoked = 1, RevokedAt = @now, RevokeReason = @reason
                WHERE Id = @id", conn, transaction);
            cmd.Parameters.AddWithValue("@now", DateTime.UtcNow);
            cmd.Parameters.AddWithValue("@reason", reason);
            cmd.Parameters.AddWithValue("@id", tokenId);
            cmd.ExecuteNonQuery();
        }

        private bool ConstantTimeEquals(string a, string b)
        {
            if (a.Length != b.Length) return false;
            int result = 0;
            for (int i = 0; i < a.Length; i++)
            {
                result |= a[i] ^ b[i];
            }
            return result == 0;
        }

        private string GenerateSecureToken(int length)
        {
            byte[] tokenBytes = new byte[length];
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(tokenBytes);
            }
            return Convert.ToBase64String(tokenBytes)
                .Replace("+", "-").Replace("/", "_").TrimEnd('=');
        }

        private string HashToken(string token)
        {
            using (var sha256 = SHA256.Create())
            {
                byte[] bytes = sha256.ComputeHash(Encoding.UTF8.GetBytes(token));
                return Convert.ToBase64String(bytes);
            }
        }

        private void ClearRememberCookie()
        {
            var cookie = new HttpCookie("RememberMe")
            {
                Expires = DateTime.Now.AddDays(-1),
                HttpOnly = true,
                Secure = true
            };
            Response.Cookies.Add(cookie);
        }

        private string GetClientIP()
        {
            string ip = Request.ServerVariables["HTTP_X_FORWARDED_FOR"];
            return string.IsNullOrEmpty(ip) ? Request.ServerVariables["REMOTE_ADDR"] : ip.Split(',')[0];
        }

        private void AlertSecurityTeam(int userId, string message)
        {
            // Integration with security monitoring (SIEM, PagerDuty, etc.)
            _logger.Fatal($"SECURITY ALERT: {message} - UserId: {userId}");
        }
    }
}
