Password reset is a critical security feature that attackers frequently target. A common vulnerability is creating reset tokens that never expire, allowing attackers to use stolen tokens indefinitely.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const nodemailer = require('nodemailer');

const app = express();
app.use(express.json());

// In-memory store (vulnerable: no expiration tracking)
const resetTokens = new Map();

app.post('/api/forgot-password', async (req, res) => {
  const { email } = req.body;

  const user = await db.findUserByEmail(email);
  if (!user) {
    return res.json({ message: 'If email exists, reset link sent' });
  }

  // VULNERABLE: Token has no expiration
  const token = crypto.randomBytes(32).toString('hex');
  resetTokens.set(token, user.id);  // No timestamp stored!

  const resetLink = `https://example.com/reset?token=${token}`;
  await sendEmail(email, resetLink);

  res.json({ message: 'If email exists, reset link sent' });
});

app.post('/api/reset-password', async (req, res) => {
  const { token, newPassword } = req.body;

  // VULNERABLE: No expiration check
  const userId = resetTokens.get(token);
  if (!userId) {
    return res.status(400).json({ error: 'Invalid token' });
  }

  // VULNERABLE: Token not invalidated after use
  const hashedPassword = await bcrypt.hash(newPassword, 10);
  await db.updatePassword(userId, hashedPassword);

  // Token remains valid for future use!
  res.json({ message: 'Password updated successfully' });
