const crypto = require('crypto');
const bcrypt = require('bcrypt');
const rateLimit = require('express-rate-limit');
const RedisStore = require('rate-limit-redis');
const Redis = require('ioredis');
const { body, validationResult } = require('express-validator');

const app = express();
app.use(express.json());

// Redis client for distributed rate limiting and token storage
const redis = new Redis({
  host: process.env.REDIS_HOST,
  port: process.env.REDIS_PORT,
  password: process.env.REDIS_PASSWORD,
  tls: process.env.NODE_ENV === 'production' ? {} : undefined
});

// Configuration
const config = {
  tokenExpiryMs: 15 * 60 * 1000,  // 15 minutes
  maxResetAttemptsPerHour: 3,      // Per email address
  maxResetAttemptsPerIp: 10,       // Per IP address
  lockoutDurationMs: 60 * 60 * 1000 // 1 hour lockout
};

// Rate limiter for password reset requests (per IP)
const resetRequestLimiter = rateLimit({
  store: new RedisStore({ sendCommand: (...args) => redis.call(...args) }),
  windowMs: 60 * 60 * 1000, // 1 hour
  max: config.maxResetAttemptsPerIp,
  message: { error: 'Too many requests, please try again later' },
  standardHeaders: true,
  legacyHeaders: false,
  keyGenerator: (req) => req.ip
});

// Rate limiter for actual password reset (per token)
const resetSubmitLimiter = rateLimit({
  store: new RedisStore({ sendCommand: (...args) => redis.call(...args) }),
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // Max 5 attempts per token
  message: { error: 'Too many attempts, please request a new reset link' },
  keyGenerator: (req) => req.body.token?.substring(0, 16) || req.ip
});

// Distributed lock for race condition prevention
async function acquireLock(key, ttlMs = 5000) {
  const lockKey = `lock:${key}`;
  const lockValue = crypto.randomBytes(16).toString('hex');

  const acquired = await redis.set(lockKey, lockValue, 'PX', ttlMs, 'NX');
  return acquired ? lockValue : null;
}

async function releaseLock(key, lockValue) {
  const lockKey = `lock:${key}`;
  const script = `
    if redis.call('get', KEYS[1]) == ARGV[1] then
      return redis.call('del', KEYS[1])
    else
      return 0
    end
  `;
  await redis.eval(script, 1, lockKey, lockValue);
}

// Check per-email rate limit
async function checkEmailRateLimit(email) {
  const key = `reset:email:${crypto.createHash('sha256').update(email.toLowerCase()).digest('hex')}`;
  const count = await redis.incr(key);

  if (count === 1) {
    await redis.expire(key, 3600); // 1 hour TTL
  }

  return count <= config.maxResetAttemptsPerHour;
}

